  1→/* Boss Assistant custom styles — supplements Simple.css */
  2→
  3→/* Toast notifications */
  4→#toast-container {
  5→    position: fixed;
  6→    top: 1rem;
  7→    right: 1rem;
  8→    z-index: 1000;
  9→    display: flex;
 10→    flex-direction: column;
 11→    gap: 0.5rem;
 12→}
 13→
 14→.toast {
 15→    padding: 0.75rem 1.25rem;
 16→    border-radius: 4px;
 17→    color: #fff;
 18→    font-size: 0.9rem;
 19→    animation: toast-in 0.3s ease, toast-out 0.3s ease 3.5s forwards;
 20→    max-width: 400px;
 21→}
 22→
 23→.toast-success { background: var(--accent, #2563eb); }
 24→.toast-error { background: #dc2626; }
 25→.toast-warning { background: #d97706; }
 26→.toast-info { background: #6b7280; }
 27→
 28→@keyframes toast-in {
 29→    from { opacity: 0; transform: translateX(100%); }
 30→    to { opacity: 1; transform: translateX(0); }
 31→}
 32→
 33→@keyframes toast-out {
 34→    from { opacity: 1; }
 35→    to { opacity: 0; }
 36→}
 37→
 38→/* Status indicators */
 39→.status-dot {
 40→    display: inline-block;
 41→    width: 10px;
 42→    height: 10px;
 43→    border-radius: 50%;
 44→    margin-right: 0.5rem;
 45→}
 46→
 47→.status-dot.online { background: #22c55e; }
 48→.status-dot.offline { background: #ef4444; }
 49→.status-dot.warning { background: #f59e0b; }
 50→
 51→/* Stat cards on dashboard */
 52→.stat-grid {
 53→    display: grid;
 54→    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
 55→    gap: 1rem;
 56→    margin: 1rem 0;
 57→}
 58→
 59→.stat-card {
 60→    padding: 1rem;
 61→    border: 1px solid var(--border);
 62→    border-radius: 4px;
 63→    text-align: center;
 64→}
 65→
 66→.stat-card .stat-value {
 67→    font-size: 2rem;
 68→    font-weight: bold;
 69→    color: var(--accent, #2563eb);
 70→}
 71→
 72→.stat-card .stat-label {
 73→    font-size: 0.85rem;
 74→    color: var(--text-light, #6b7280);
 75→}
 76→
 77→/* Progress bar */
 78→.progress-bar {
 79→    width: 100%;
 80→    height: 20px;
 81→    background: var(--bg-secondary, #e5e7eb);
 82→    border-radius: 10px;
 83→    overflow: hidden;
 84→    margin: 0.5rem 0;
 85→}
 86→
 87→.progress-bar .progress-fill {
 88→    height: 100%;
 89→    background: var(--accent, #2563eb);
 90→    border-radius: 10px;
 91→    transition: width 0.3s ease;
 92→}
 93→
 94→/* Pipeline log */
 95→.pipeline-log {
 96→    max-height: 400px;
 97→    overflow-y: auto;
 98→    padding: 1rem;
 99→    background: var(--bg-secondary, #f3f4f6);
100→    border-radius: 4px;
101→    font-family: monospace;
102→    font-size: 0.85rem;
103→    line-height: 1.6;
104→}
105→
106→.pipeline-log .log-entry {
107→    padding: 0.25rem 0;
108→    border-bottom: 1px solid var(--border, #e5e7eb);
109→}
110→
111→.pipeline-log .log-entry:last-child {
112→    border-bottom: none;
113→}
114→
115→/* HTMX loading indicator */
116→.htmx-indicator {
117→    display: none;
118→}
119→
120→.htmx-request .htmx-indicator,
121→.htmx-request.htmx-indicator {
122→    display: inline-block;
123→}
124→
125→/* Disabled state for buttons during pipeline */
126→button[disabled], input[disabled] {
127→    opacity: 0.6;
128→    cursor: not-allowed;
129→}
130→
131→/* Tag pills */
132→.tag {
133→    display: inline-block;
134→    padding: 0.15rem 0.5rem;
135→    background: var(--accent-bg, #dbeafe);
136→    color: var(--accent, #2563eb);
137→    border-radius: 12px;
138→    font-size: 0.8rem;
139→    margin: 0.1rem;
140→}
141→

  1→<div id="pipeline-progress"
  2→     hx-ext="sse"
  3→     sse-connect="/pipeline/progress/{{ task_id }}"
  4→     sse-close="done">
  5→
  6→    <h3>Pipeline 运行中: {{ task_id }}</h3>
  7→
  8→    <div class="progress-bar">
  9→        <div class="progress-fill" id="progress-fill" style="width: 0%;"></div>
 10→    </div>
 11→
 12→    <p id="progress-status">初始化...</p>
 13→
 14→    <div class="pipeline-log" id="pipeline-log">
 15→    </div>
 16→
 17→    <button hx-delete="/pipeline/cancel" hx-swap="none"
 18→            onclick="this.disabled=true; this.textContent='取消中...';">
 19→        取消 Pipeline
 20→    </button>
 21→</div>
 22→
 23→<div sse-swap="search_start" hx-swap="none" style="display:none;"></div>
 24→<div sse-swap="search_complete" hx-swap="none" style="display:none;"></div>
 25→<div sse-swap="scoring_start" hx-swap="none" style="display:none;"></div>
 26→<div sse-swap="scoring_complete" hx-swap="none" style="display:none;"></div>
 27→<div sse-swap="send_start" hx-swap="none" style="display:none;"></div>
 28→<div sse-swap="send_complete" hx-swap="none" style="display:none;"></div>
 29→<div sse-swap="pipeline_complete" hx-swap="none" style="display:none;"></div>
 30→<div sse-swap="captcha_detected" hx-swap="none" style="display:none;"></div>
 31→<div sse-swap="error" hx-swap="none" style="display:none;"></div>
 32→<div sse-swap="pipeline_cancelled" hx-swap="none" style="display:none;"></div>
 33→<div sse-swap="done" hx-swap="none" style="display:none;"></div>
 34→
 35→<script>
 36→(function() {
 37→    const log = document.getElementById("pipeline-log");
 38→    const status = document.getElementById("progress-status");
 39→    const fill = document.getElementById("progress-fill");
 40→
 41→    function addLog(text) {
 42→        const entry = document.createElement("div");
 43→        entry.className = "log-entry";
 44→        entry.textContent = new Date().toLocaleTimeString() + " — " + text;
 45→        log.appendChild(entry);
 46→        log.scrollTop = log.scrollHeight;
 47→    }
 48→
 49→    function setProgress(pct) {
 50→        fill.style.width = pct + "%";
 51→    }
 52→
 53→    const source = document.getElementById("pipeline-progress")
 54→        .__sse_eventSource || null;
 55→
 56→    // Listen to SSE events via custom event listeners
 57→    const container = document.getElementById("pipeline-progress");
 58→    if (!container) return;
 59→
 60→    const sseEl = container;
 61→    const events = [
 62→        "search_start", "search_complete", "scoring_start", "scoring_complete",
 63→        "send_start", "send_complete", "pipeline_complete", "captcha_detected",
 64→        "error", "pipeline_cancelled", "done"
 65→    ];
 66→
 67→    // Use EventSource directly for richer control
 68→    const taskId = "{{ task_id }}";
 69→    const es = new EventSource("/pipeline/progress/" + taskId);
 70→
 71→    es.addEventListener("search_start", function(e) {
 72→        const d = JSON.parse(e.data);
 73→        status.textContent = "搜索中: " + (d.keywords || []).join(", ");
 74→        setProgress(10);
 75→        addLog("开始搜索: " + (d.keywords || []).join(", "));
 76→    });
 77→
 78→    es.addEventListener("search_complete", function(e) {
 79→        const d = JSON.parse(e.data);
 80→        status.textContent = "搜索完成，找到 " + d.total_candidates + " 个候选人";
 81→        setProgress(30);
 82→        addLog("搜索完成: " + d.total_candidates + " 个候选人");
 83→    });
 84→
 85→    es.addEventListener("scoring_start", function(e) {
 86→        const d = JSON.parse(e.data);
 87→        status.textContent = "评分中 (" + d.count + " 个候选人)...";
 88→        setProgress(40);
 89→        addLog("开始评分: " + d.count + " 个候选人");
 90→    });
 91→
 92→    es.addEventListener("scoring_complete", function(e) {
 93→        const d = JSON.parse(e.data);
 94→        status.textContent = "评分完成，最高分: " + d.top_score;
 95→        setProgress(50);
 96→        addLog("评分完成, 最高分: " + d.top_score);
 97→    });
 98→
 99→    es.addEventListener("send_start", function(e) {
100→        const d = JSON.parse(e.data);
101→        status.textContent = "发送消息中 (0/" + d.total + ")...";
102→        setProgress(55);
103→        addLog("开始发送消息: " + d.total + " 个候选人");
104→    });
105→
106→    es.addEventListener("send_complete", function(e) {
107→        const d = JSON.parse(e.data);
108→        status.textContent = "发送完成: 成功 " + (d.sent||0) + ", 失败 " + (d.failed||0);
109→        setProgress(90);
110→        addLog("发送完成: 成功=" + (d.sent||0) + " 失败=" + (d.failed||0) + " 跳过=" + (d.skipped||0));
111→    });
112→
113→    es.addEventListener("pipeline_complete", function(e) {
114→        const d = JSON.parse(e.data);
115→        status.textContent = "Pipeline 完成!";
116→        setProgress(100);
117→        addLog("Pipeline 完成: 候选人=" + (d.candidates_found||0) + " 发送=" + (d.sent||0));
118→    });
119→
120→    es.addEventListener("captcha_detected", function(e) {
121→        status.textContent = "验证码检测到! 请在 Chrome 窗口中处理";
122→        addLog("⚠️ 验证码检测到，请在 Chrome 中手动处理");
123→        showToast("验证码检测到！请在 Chrome 窗口中处理", "warning");
124→    });
125→
126→    es.addEventListener("error", function(e) {
127→        try {
128→            const d = JSON.parse(e.data);
129→            addLog("❌ 错误: " + d.message);
130→            showToast("Pipeline 错误: " + d.message, "error");
131→        } catch(ex) {}
132→    });
133→
134→    es.addEventListener("pipeline_cancelled", function(e) {
135→        status.textContent = "Pipeline 已取消";
136→        addLog("Pipeline 已取消");
137→    });
138→
139→    es.addEventListener("done", function(e) {
140→        es.close();
141→        addLog("— 结束 —");
142→    });
143→
144→    es.onerror = function() {
145→        es.close();
146→    };
147→})();
148→</script>
